import { ApiResponse } from "./apiResponse.js";
import { Document } from "./document.js";
/** Wrapper for synchronous prediction response.
 *
 * @category API Response
 * @category Synchronous
 */
export class PredictResponse extends ApiResponse {
    /**
     *
     * @param inferenceClass constructor signature for an inference.
     * @param serverResponse raw http response.
     */
    constructor(inferenceClass, serverResponse) {
        super(serverResponse);
        this.document = new Document(inferenceClass, serverResponse["document"]);
    }
}
